import{_ as a,o as t,c as i,ag as n}from"./chunks/framework.BPmc_f4o.js";const g=JSON.parse('{"title":"Global IP Filtering","description":"","frontmatter":{},"headers":[],"relativePath":"global-ip-filtering/global-ip-filtering.md","filePath":"global-ip-filtering/global-ip-filtering.md"}'),o={name:"global-ip-filtering/global-ip-filtering.md"};function l(r,e,s,p,c,h){return t(),i("div",null,[...e[0]||(e[0]=[n(`<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#2e7d32;color:#fff;font-size:11px;font-weight:600;">FREE</span> <span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="global-ip-filtering" tabindex="-1">Global IP Filtering <a class="header-anchor" href="#global-ip-filtering" aria-label="Permalink to &quot;Global IP Filtering&quot;">​</a></h1><p>Global IP Filtering is a network-level firewall layer that runs <strong>before application resolution</strong>. Every incoming REST request is evaluated against the global blocklist regardless of which application it targets. A blocked IP or country never reaches application-specific logic.</p><p>This complements the <a href="/ipsfilter/ipsfilter.html">Per-Application IP Filtering</a> module (Pro only), which adds application-scoped rules on top. Use Global IP Filtering for shared threats — known bots, attack infrastructure, unwanted geographies. Use per-application IP Filtering for rules specific to one application.</p><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Incoming REST request</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────────────┐</span></span>
<span class="line"><span>│  Global IP Filtering    │  ← Shared blocklist: IPs, CIDRs, countries (runs first)</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │  blocked → 403</span></span>
<span class="line"><span>             ▼</span></span>
<span class="line"><span>┌─────────────────────────┐</span></span>
<span class="line"><span>│  Application Matching   │  ← Which application owns this request? (Pro)</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>             ▼</span></span>
<span class="line"><span>        … rest of pipeline</span></span></code></pre></div><p>The global check fires on the <code>rest_authentication_errors</code> hook at priority 10, before any application-resolution filter runs. Admin-authenticated requests bypass the check entirely.</p><hr><h2 id="free-tier" tabindex="-1">Free Tier <a class="header-anchor" href="#free-tier" aria-label="Permalink to &quot;Free Tier&quot;">​</a></h2><h3 id="manual-blocklist" tabindex="-1">Manual Blocklist <a class="header-anchor" href="#manual-blocklist" aria-label="Permalink to &quot;Manual Blocklist&quot;">​</a></h3><p>Add IPv4 addresses to the global blocklist manually. Blocked IPs receive a <code>403</code> response immediately.</p><h3 id="geoip-statistics" tabindex="-1">GeoIP Statistics <a class="header-anchor" href="#geoip-statistics" aria-label="Permalink to &quot;GeoIP Statistics&quot;">​</a></h3><p>Read-only geographic statistics of incoming requests are visible. Country-level blocking requires Pro.</p><hr><h2 id="pro-tier" tabindex="-1">Pro Tier <a class="header-anchor" href="#pro-tier" aria-label="Permalink to &quot;Pro Tier&quot;">​</a></h2><h3 id="cidr-ranges" tabindex="-1">CIDR Ranges <a class="header-anchor" href="#cidr-ranges" aria-label="Permalink to &quot;CIDR Ranges&quot;">​</a></h3><p>Block entire IP ranges using CIDR notation (e.g. <code>10.0.0.0/8</code>, <code>192.168.1.0/24</code>). Supports both IPv4 and IPv6.</p><h3 id="country-blocking" tabindex="-1">Country Blocking <a class="header-anchor" href="#country-blocking" aria-label="Permalink to &quot;Country Blocking&quot;">​</a></h3><p>Block all requests originating from one or more countries using GeoIP data. Country rules are evaluated after the IP/CIDR check. Configuring no countries disables the country check entirely — there is no performance cost when the list is empty.</p><h3 id="retention-time" tabindex="-1">Retention Time <a class="header-anchor" href="#retention-time" aria-label="Permalink to &quot;Retention Time&quot;">​</a></h3><p>Set a global retention period. Entries without a specific expiry inherit this value and are automatically removed when it elapses.</p><hr><h2 id="ip-list-management" tabindex="-1">IP List Management <a class="header-anchor" href="#ip-list-management" aria-label="Permalink to &quot;IP List Management&quot;">​</a></h2><p>The IP list shows all active global entries. For each entry:</p><ul><li><strong>Add</strong> an IP or CIDR range manually.</li><li><strong>Delete</strong> one or more entries individually or in bulk.</li></ul><p>Entries show the IP address, source (manual or auto-detected), detected country, and — in Pro — the expiry time.</p><hr><h2 id="relationship-to-per-application-ip-filtering" tabindex="-1">Relationship to Per-Application IP Filtering <a class="header-anchor" href="#relationship-to-per-application-ip-filtering" aria-label="Permalink to &quot;Relationship to Per-Application IP Filtering&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Tier</th><th>Scope</th><th>Runs at</th></tr></thead><tbody><tr><td>Global IP Filtering</td><td>Free + Pro</td><td>All applications</td><td>Before application resolution</td></tr><tr><td>Per-Application IP Filtering</td><td><strong>Pro only</strong></td><td>One application</td><td>After application resolution</td></tr></tbody></table><p>An IP that passes the global check can still be blocked at the per-application level. An IP blocked globally never reaches application logic.</p><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>Does the global blocklist affect admin users?</strong></p><p>No. Requests from logged-in administrators bypass the global check.</p><p><strong>Can I use Global IP Filtering without Pro?</strong></p><p>Yes. Manual IPv4 blocking is available in the free tier. CIDR ranges, country blocking, and retention time require Pro.</p><p><strong>Where do auto-blacklisted IPs from rate limiting go?</strong></p><p>Rate-limit auto-blacklisting writes to the global list.</p><p><strong>What HTTP status does a blocked request receive?</strong></p><p><code>403 Forbidden</code> with a JSON error body.</p>`,41)])])}const u=a(o,[["render",l]]);export{g as __pageData,u as default};
